<template>
	<view class="page-container">
		<!-- Тљюу┤бТАє -->
		<view class="search-box">
			<text class="search-label">ТЌЦТюЪТљюу┤б</text>
			<uni-datetime-picker 
				type="date" 
				v-model="searchDatePicker"
				placeholder="У»ижђЅТІЕТЌЦТюЪ"
				@change="onSearchDateChange"
			/>
		</view>
		
		<!-- тѕЌУАе -->
		<view class="list-section">
			<view 
				class="list-item" 
				v-for="(item,i) in list" 
				:key="i" 
				@click="editInfo(item)"
			>
				<text class="item-date">{{item.date}}</text>
				<text class="item-title">{{item.title}}</text>
				<text class="item-arrow">Рђ║</text>
			</view>
			
			<view v-if="!list.length" class="empty-list">
				<text>ТџѓТЌаТЋ░ТЇ«</text>
			</view>
		</view>
		
		<!-- УАетЇЋ -->
		<view class="form-section">
			<form>
				<view class="form-item">
					<text class="form-label">ТЌЦТюЪ</text>
					<uni-datetime-picker 
						class="form-input"
						type="date" 
						v-model="formDatePicker"
						placeholder="У»ижђЅТІЕТЌЦТюЪ"
						@change="onFormDateChange"
					/>
				</view>
				
				<view class="form-item">
					<text class="form-label">ТаЄжбў</text>
					<input 
						class="form-input" 
						name="title" 
						v-model="formData.title" 
						placeholder="У»иУЙЊтЁЦТаЄжбў"
					/>
				</view>
				
				<view class="form-item">
					<text class="form-label">тцЄТ│е</text>
					<textarea 
						class="form-textarea" 
						name="bz" 
						v-model="formData.bz" 
						placeholder="У»иУЙЊтЁЦтцЄТ│е"
					/>
				</view>
				<view class="form-item">
					<text class="form-label">у▒╗тъІ</text>
					<input 
						class="form-input" 
						name="title" 
						v-model="formData.type" 
						placeholder="1жЄЇУдЂ№╝ї2у│ќ"
					/>
				</view>
				
				<view class="form-item">
					<text class="form-label">тЏЙуЅЄУи»тЙё</text>
					<textarea 
						class="form-textarea" 
						name="imgurl" 
						v-model="formData.imgurl" 
						placeholder="У»иУЙЊтЁЦтЏЙуЅЄУи»тЙё№╝їтцџСИфућетѕєтЈижџћт╝ђ"
					/>
				</view>
				
				<image-upload 
						ref="imageUpload"
						title="СИіС╝атЏЙуЅЄ" 
						optionalText="С╝ўтЁѕтцќжЊЙ" 
						maxCount="3"
						uploadPath="rili"
						:modelValue="formData.imgurl"
					></image-upload>
				
				<view class="form-actions" v-if="formData._id">
					<button 
						type="primary" 
						class="action-btn update-btn" 
						@click="submit('update')"
					>
						ТЏ┤Тќ░
					</button>
					<button 
						type="primary" 
						class="action-btn delete-btn" 
						@click="remove(formData._id)"
						v-if=" isCalendarPermission('del') "
					>
						тѕажЎц
					</button>
					<button 
						type="primary" 
						class="action-btn clear-btn" 
						@click="clearForm"
					>
						ТИЁуЕ║
					</button>
				</view>
				
				<button 
					type="primary" 
					class="action-btn save-btn full-width" 
					@click="submit('add')" 
					v-else
				>
					С┐ЮтГў
				</button>
			</form>
		</view>
		
		<!-- жЌ«тђЎУ»ГУ«Йуй« -->
		<view class="greeting-section">
			<view class="section-title">
				<text class="title-icon">­Ъћћ</text>
				<text>жЌ«тђЎУ»ГУ«Йуй«</text>
			</view>
			<form>
				<view class="form-item">
					<text class="form-label">жЌ«тђЎУ»Г</text>
					<input 
						class="form-input" 
						name="greeting" 
						v-model="customGreeting.title" 
						placeholder="У»иУЙЊтЁЦжЌ«тђЎУ»Г"
					/>
				</view>
				
				<button 
					type="primary" 
					class="action-btn save-btn full-width" 
					@click="add_customGreeting"
				>
					С┐ЮтГўжЌ«тђЎУ»Г
				</button>
			</form>
		</view>
		
		
	</view>
</template>

<script>
import { hasCalendarPermission } from '@/common/js/permission.js'
	export default{
		data(){
			return{
				list:[],
				formData:{
					title:'',
					bz:'',
					date:'',
					imgurl:'',
					type:''
				},
				search:{
					date:''
				},
				searchDatePicker: '',
				formDatePicker: '',
				customGreeting:{
					title:''
				},
				userInfo:null,
			}
		},
		onLoad() {
			const userInfo = uni.getStorageSync('userInfo');
			this.userInfo=JSON.parse(userInfo)
		},
		methods:{
			isCalendarPermission(type) {
				return hasCalendarPermission(this.userInfo, type)
			},
			editInfo(data){
				this.formData = {...data}
				this.formDatePicker = data.date ? this.formatToPicker(data.date) : ''
			},
			formatToPicker(dateStr) {
				if (!dateStr) return ''
				const parts = dateStr.split('-')
				if (parts.length === 3) {
					return `${parts[0]}-${String(parts[1]).padStart(2, '0')}-${String(parts[2]).padStart(2, '0')}`
				}
				return dateStr
			},
			formatDate(dateStr) {
				if (!dateStr) return ''
				const parts = dateStr.split('-')
				if (parts.length === 3) {
					return `${parts[0]}-${parseInt(parts[1])}-${parseInt(parts[2])}`
				}
				return dateStr
			},
			onSearchDateChange() {
				this.search.date = this.formatDate(this.searchDatePicker)
				this.getList()
			},
			onFormDateChange() {
				this.formData.date = this.formatDate(this.formDatePicker)
			},
			add_customGreeting(){
				if(!this.customGreeting.title&&!this.customGreeting.bgcolor){
					uni.showModal({
						content: `У»иУЙЊтЁЦТюЅТЋѕТЋ░ТЇ«`,
						showCancel: false
					})
					return
					
				}
				uni.showLoading({
					title: 'тцёуљєСИГ...'
				})
				uniCloud.callFunction({
					name: 'welcome',
					data: {
						type:'update',
						params:this.customGreeting,
					}
				}).then((res) => {
					uni.hideLoading()
					uni.showModal({
						content: `жЌ«тђЎУ»ГС┐«Тћ╣ТѕљтіЪ`,
						showCancel: false
					})
					this.clearForm()
				}).catch((err) => {
					uni.hideLoading()
					uni.showModal({
						content: `С┐«Тћ╣ТЋ░ТЇ«тц▒У┤Ц`,
						showCancel: false
					})
					console.error(err)
				})
			},
			async setImg(){
				const isEdit = !!this.formData._id
				const result = await this.$refs.imageUpload.processImages(isEdit)
				if (result !== null) {
					this.formData.imgurl = result
				}
			},
			async add() {
				if(!this.formData.date){
					uni.showModal({
						content: `У»ижђЅТІЕТЌЦТюЪ`,
						showCancel: false
					})
					return
				}
				if(!this.formData.title){
					uni.showModal({
						content: `У»иУЙЊтЁЦТаЄжбў`,
						showCancel: false
					})
					return
				}
				await this.setImg()
				uni.showLoading({
					title: 'тцёуљєСИГ...'
				})
				let params = {...this.formData,add_czr:this.userInfo._id}
				uniCloud.callFunction({
					name: 'rili-add',
					data: {
						type:'add',
						params
					}
				}).then((res) => {
					uni.hideLoading()
					uni.showModal({
						content: `ТѕљтіЪТи╗тіаСИђТЮАТЋ░ТЇ«№╝їТќЄТАБidСИ║№╝џ${res.result.id}`,
						showCancel: false
					})
					this.clearForm()
				}).catch((err) => {
					uni.hideLoading()
					uni.showModal({
						content: `Ти╗тіаТЋ░ТЇ«тц▒У┤Ц№╝їжћЎУ»»С┐АТЂ»СИ║№╝џ${err.message}`,
						showCancel: false
					})
					console.error(err)
				})
			},
			remove(id) {
				uni.showLoading({
					title: 'тцёуљєСИГ...'
				})
				uniCloud.callFunction({
					name: 'rili-add',
					data: {
						type:'del',
						params:this.formData._id
					}
				}).then((res) => {
					uni.hideLoading()
					uni.showModal({
						content: `тѕажЎцТѕљтіЪ`,
						showCancel: false
					})
					this.getList()
					this.clearForm()
					//console.log(res)
				}).catch((err) => {
					uni.hideLoading()
					uni.showModal({
						content: `тѕажЎцтц▒У┤Ц№╝їжћЎУ»»С┐АТЂ»СИ║№╝џ${err.message}`,
						showCancel: false
					})
					console.error(err)
				})
			},
			async update() {
				if(!this.formData.date){
					uni.showModal({
						content: `У»ижђЅТІЕТЌЦТюЪ`,
						showCancel: false
					})
					return
				}
				if(!this.formData.title){
					uni.showModal({
						content: `У»иУЙЊтЁЦТаЄжбў`,
						showCancel: false
					})
					return
				}
				await this.setImg()
				uni.showLoading({
					title: 'тцёуљєСИГ...'
				})
				let params = {...this.formData,update_czr:this.userInfo._id}
				uniCloud.callFunction({
					name: 'rili-add',
					data: {
						type:'update',
						params
					}
				}).then((res) => {
					uni.hideLoading()
					uni.showModal({
						content: `ТЏ┤Тќ░ТѕљтіЪ`,
						showCancel: false
					})
					this.getList()
					this.clearForm()
					//console.log(res)
				}).catch((err) => {
					uni.hideLoading()
					uni.showModal({
						content: `ТЏ┤Тќ░ТЊЇСйюТЅДУАїтц▒У┤Ц№╝їжћЎУ»»С┐АТЂ»СИ║№╝џ${err.message}`,
						showCancel: false
					})
					console.error(err)
				})
			},
			submit(type) {
				if(type==='add'){
					this.add()
				}else if(type==='update'){
					this.update()
				}
			},
			getList() {
				
				uni.showLoading({
					title: 'тцёуљєСИГ...'
				})
				uniCloud.callFunction({
					name: 'rili-get',
					data:{
						search:this.search
					}
				}).then((res) => {
					uni.hideLoading()
					
					this.list=res.result.data ||[]
				}).catch((err) => {
					uni.hideLoading()
					uni.showModal({
						content: `ТЪЦУ»бтц▒У┤Ц№╝їжћЎУ»»С┐АТЂ»СИ║№╝џ${err.message}`,
						showCancel: false
					})
					console.error(err)
				})
			},
			clearForm(){
				
				delete this.formData._id
				this.formData.date=''
				this.formData.title=''
				this.formData.bz=''
				this.formData.imgurl=''
				if (this.$refs.imageUpload) {
					this.$refs.imageUpload.clearImages()
				}
			},
		}
	}
</script>

<style lang="scss">
