		}
		
		text {
			font-size: 16px;
			font-weight: 600;
			color: #333;
		}
	}
	
	.form-item {
		margin-bottom: 16px;
		
		.form-label {
			display: block;
			font-size: 14px;
			color: #666;
			margin-bottom: 8px;
			font-weight: 500;
		}
		
		.form-input {
			width: 100%;
			height: 44px;
			background: #f5f7fa;
			border-radius: 8px;
			padding: 0 12px;
			font-size: 15px;
		}
	}
	
	.action-btn {
		width: 100%;
		height: 44px;
		line-height: 44px;
		border-radius: 8px;
		font-size: 15px;
		font-weight: 500;
		border: none;
		background: linear-gradient(135deg, #aaa1ce 0%, #9b8fbf 100%);
		color: #fff;
	}
}

// С┐ЮуЋЎТЌДТаит╝Ј
.flex-row {
	display: flex;
}

.title {
	color: cadetblue;
}

.page {
	padding: 5px;
}

.uni-form-item {
	margin-bottom: 10px;
}

.search-box {
	background: #eee;
